'use client';

import React from 'react';
import { DollarSign, TrendingUp, AlertTriangle, Users, CreditCard } from 'lucide-react';

interface TuitionSummaryCardsProps {
  totalReceived: number;
  totalReceivable: number;
  totalDebt: number;
  debtorCount: number;
  isLoading?: boolean;
}

const fmt = (n: number | undefined | null) =>
  (n || 0).toLocaleString('vi-VN') + 'đ';

function SkeletonCard() {
  return (
    <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm animate-pulse">
      <div className="flex justify-between items-start mb-4">
        <div className="h-3 w-24 bg-slate-200 rounded" />
        <div className="h-10 w-10 bg-slate-100 rounded-xl" />
      </div>
      <div className="h-8 w-36 bg-slate-200 rounded mb-2" />
      <div className="h-3 w-20 bg-slate-100 rounded" />
    </div>
  );
}

export default function TuitionSummaryCards({
  totalReceived,
  totalReceivable,
  totalDebt,
  debtorCount,
  isLoading = false,
}: TuitionSummaryCardsProps) {
  if (isLoading) {
    return (
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {Array.from({ length: 4 }).map((_, i) => (
          <SkeletonCard key={i} />
        ))}
      </div>
    );
  }

  const paid = totalReceived;
  const pending = totalReceivable - totalReceived;
  const collectionRate = totalReceivable > 0 ? Math.round((paid / totalReceivable) * 100) : 0;

  return (
    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
      {/* Total Receivable — deep navy hero card */}
      <div className="col-span-2 lg:col-span-1 bg-gradient-to-br from-[#0f172a] to-[#1e3a8a] rounded-2xl p-6 text-white relative overflow-hidden min-h-[148px] flex flex-col justify-between">
        <div className="absolute top-4 right-4 opacity-10">
          <CreditCard className="w-24 h-24" />
        </div>
        <div className="relative z-10">
          <div className="flex items-center justify-between mb-3">
            <span className="text-[11px] font-bold text-white/60 uppercase tracking-widest">
              Tổng phải thu
            </span>
            <div className="w-9 h-9 rounded-xl bg-white/10 flex items-center justify-center backdrop-blur-sm">
              <CreditCard className="w-4 h-4 text-white/70" />
            </div>
          </div>
          <h3 className="text-2xl font-black text-white tabular-nums leading-none mb-2">
            {fmt(totalReceivable)}
          </h3>
        </div>
        <div className="relative z-10 flex items-center gap-2">
          <div className="flex-1 h-1.5 bg-white/20 rounded-full overflow-hidden">
            <div
              className="h-full bg-emerald-400 rounded-full transition-all duration-700"
              style={{ width: `${collectionRate}%` }}
            />
          </div>
          <span className="text-[10px] font-bold text-white/60 tabular-nums">{collectionRate}%</span>
        </div>
      </div>

      {/* Collected / Paid */}
      <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm flex flex-col justify-between gap-3 min-h-[148px] hover:shadow-md transition-shadow group">
        <div className="flex items-center justify-between">
          <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
            Đã thu
          </span>
          <div className="w-9 h-9 rounded-xl bg-emerald-50 flex items-center justify-center group-hover:scale-110 transition-transform">
            <TrendingUp className="w-4 h-4 text-emerald-600" />
          </div>
        </div>
        <div>
          <h3 className="text-2xl font-black text-slate-900 tabular-nums leading-none mb-1">
            {fmt(paid)}
          </h3>
          <span className="text-[11px] font-semibold text-emerald-600">
            {collectionRate}% của tổng phải thu
          </span>
        </div>
      </div>

      {/* Pending / Unpaid */}
      <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm flex flex-col justify-between gap-3 min-h-[148px] hover:shadow-md transition-shadow group">
        <div className="flex items-center justify-between">
          <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
            Chưa thu
          </span>
          <div className="w-9 h-9 rounded-xl bg-amber-50 flex items-center justify-center group-hover:scale-110 transition-transform">
            <AlertTriangle className="w-4 h-4 text-amber-600" />
          </div>
        </div>
        <div>
          <h3 className="text-2xl font-black text-amber-600 tabular-nums leading-none mb-1">
            {fmt(pending)}
          </h3>
          <span className="text-[11px] font-semibold text-slate-400">
            {totalReceivable - debtorCount > 0 ? `${totalReceivable - debtorCount} HV chưa đóng đủ` : 'Tất cả đã đóng đủ'}
          </span>
        </div>
      </div>

      {/* Overdue / Debtor count */}
      <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm flex flex-col justify-between gap-3 min-h-[148px] hover:shadow-md transition-shadow group">
        <div className="flex items-center justify-between">
          <span className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">
            Quá hạn
          </span>
          <div className="w-9 h-9 rounded-xl bg-rose-50 flex items-center justify-center group-hover:scale-110 transition-transform">
            <Users className="w-4 h-4 text-rose-600" />
          </div>
        </div>
        <div>
          <h3 className="text-2xl font-black text-rose-600 tabular-nums leading-none mb-1">
            {fmt(totalDebt)}
          </h3>
          <span className="text-[11px] font-semibold text-slate-400">
            {debtorCount} học viên còn nợ
          </span>
        </div>
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { Search, SlidersHorizontal, X } from 'lucide-react';

export interface TuitionFiltersState {
  search: string;
  status: string;
  dateFrom: string;
  dateTo: string;
}

interface TuitionFiltersProps {
  filters: TuitionFiltersState;
  onChange: (filters: TuitionFiltersState) => void;
  isLoading?: boolean;
}

export default function TuitionFilters({
  filters,
  onChange,
  isLoading = false,
}: TuitionFiltersProps) {
  const update = (patch: Partial<TuitionFiltersState>) =>
    onChange({ ...filters, ...patch });

  const hasActiveFilters =
    filters.status ||
    filters.dateFrom ||
    filters.dateTo ||
    filters.search.length > 0;

  const clearAll = () =>
    onChange({ search: '', status: '', dateFrom: '', dateTo: '' });

  return (
    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-4 flex flex-col lg:flex-row gap-3 items-start lg:items-center">
      {/* Search */}
      <div className="relative flex-1 w-full lg:max-w-xs">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" />
        <input
          type="text"
          value={filters.search}
          onChange={e => update({ search: e.target.value })}
          placeholder="Tìm tên, mã phiếu, SĐT…"
          className="w-full pl-9 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm text-slate-700 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all disabled:opacity-50"
          disabled={isLoading}
        />
      </div>

      {/* Status */}
      <select
        value={filters.status}
        onChange={e => update({ status: e.target.value })}
        disabled={isLoading}
        className="px-3 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary cursor-pointer transition-all disabled:opacity-50 min-w-[160px]"
      >
        <option value="">Tất cả trạng thái</option>
        <option value="done">Đã đóng</option>
        <option value="partial">Đóng 1 phần</option>
        <option value="debt">Còn nợ</option>
      </select>

      {/* Date range */}
      <div className="flex items-center gap-2 flex-wrap">
        <div className="flex items-center gap-1.5 text-xs font-semibold text-slate-400">
          <SlidersHorizontal className="w-3.5 h-3.5" />
          Từ
        </div>
        <input
          type="date"
          value={filters.dateFrom}
          onChange={e => update({ dateFrom: e.target.value })}
          disabled={isLoading}
          className="px-3 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary cursor-pointer transition-all disabled:opacity-50"
        />
        <div className="flex items-center gap-1.5 text-xs font-semibold text-slate-400">
          Đến
        </div>
        <input
          type="date"
          value={filters.dateTo}
          onChange={e => update({ dateTo: e.target.value })}
          disabled={isLoading}
          className="px-3 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary cursor-pointer transition-all disabled:opacity-50"
        />
      </div>

      {/* Clear all */}
      {hasActiveFilters && (
        <button
          onClick={clearAll}
          disabled={isLoading}
          className="flex items-center gap-1.5 px-3 py-2 text-xs font-bold text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-lg transition-colors disabled:opacity-50"
        >
          <X className="w-3.5 h-3.5" />
          Xóa lọc
        </button>
      )}
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import {
  ChevronUp,
  ChevronDown,
  ChevronsUpDown,
  Eye,
  ChevronLeft,
  ChevronRight,
  Loader2,
} from 'lucide-react';

type SortKey = 'name' | 'paid' | 'total' | 'debt' | 'date' | 'status';
type SortDir = 'asc' | 'desc';

const fmt = (n: number | undefined | null) =>
  (n || 0).toLocaleString('vi-VN') + 'đ';

interface PaymentItem {
  _id: string;
  received_fee?: number;
  payment_date?: string;
  is_tuition_account?: boolean;
  course_student_id?: {
    _id?: string;
    fee?: number;
    paid_fee?: number;
    student_id?: {
      _id?: string;
      user_id?: {
        _id?: string;
        first_name?: string;
        last_name?: string;
        phone?: string;
      };
      region_id?: { name?: string };
    };
    course_id?: {
      name?: string;
      license_category_id?: { name?: string };
    };
  };
}

interface TuitionTableProps {
  payments: PaymentItem[];
  meta: any;
  currentPage: number;
  isLoading?: boolean;
  onPageChange: (page: number) => void;
  onViewDetail: (item: PaymentItem) => void;
}

function StatusBadge({ debt, paid }: { debt: number; paid: number }) {
  if (debt === 0) {
    return (
      <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-[11px] font-bold bg-emerald-50 text-emerald-700 border border-emerald-200">
        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
        Đã đóng
      </span>
    );
  }
  if (paid === 0) {
    return (
      <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-[11px] font-bold bg-rose-50 text-rose-700 border border-rose-200">
        <span className="w-1.5 h-1.5 rounded-full bg-rose-500" />
        Quá hạn
      </span>
    );
  }
  return (
    <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-[11px] font-bold bg-amber-50 text-amber-700 border border-amber-200">
      <span className="w-1.5 h-1.5 rounded-full bg-amber-500" />
      Đóng 1 phần
    </span>
  );
}

function SortIcon({ column, sortKey, sortDir }: { column: SortKey; sortKey: SortKey; sortDir: SortDir }) {
  if (sortKey !== column) return <ChevronsUpDown className="w-3.5 h-3.5 text-slate-300" />;
  return sortDir === 'asc'
    ? <ChevronUp className="w-3.5 h-3.5 text-primary" />
    : <ChevronDown className="w-3.5 h-3.5 text-primary" />;
}

export default function TuitionTable({
  payments,
  meta,
  currentPage,
  isLoading = false,
  onPageChange,
  onViewDetail,
}: TuitionTableProps) {
  const [sortKey, setSortKey] = useState<SortKey>('date');
  const [sortDir, setSortDir] = useState<SortDir>('desc');

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDir(d => (d === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortKey(key);
      setSortDir('desc');
    }
  };

  // Build sortable rows
  const rows: (PaymentItem & { _debt: number; _paid: number; _total: number; _name: string; _date: string })[] = payments.map(p => {
    const cs = p.course_student_id || {};
    const student = cs.student_id?.user_id || {};
    const _paid = p.received_fee || cs.paid_fee || 0;
    const _total = cs.fee || 0;
    const _debt = _total - _paid;
    const _name = `${student.last_name || ''} ${student.first_name || ''}`.trim() || 'Ẩn danh';
    const _date = p.payment_date || '';
    return { ...p, _debt, _paid, _total, _name, _date };
  });

  const sorted = [...rows].sort((a, b) => {
    let cmp = 0;
    switch (sortKey) {
      case 'name': cmp = a._name.localeCompare(b._name); break;
      case 'paid': cmp = a._paid - b._paid; break;
      case 'total': cmp = a._total - b._total; break;
      case 'debt': cmp = a._debt - b._debt; break;
      case 'date': cmp = a._date.localeCompare(b._date); break;
      case 'status':
        if (a._debt === 0 && b._debt !== 0) cmp = -1;
        else if (a._debt !== 0 && b._debt === 0) cmp = 1;
        else cmp = a._paid - b._paid;
        break;
    }
    return sortDir === 'asc' ? cmp : -cmp;
  });

  const totalPages = meta?.total_pages || 1;
  const totalItems = meta?.total || 0;
  const startItem = (currentPage - 1) * (meta?.limit || 20) + 1;
  const endItem = Math.min(currentPage * (meta?.limit || 20), totalItems);

  const thCls = (key: SortKey) =>
    `px-4 py-3.5 text-[10px] font-bold uppercase tracking-wider text-slate-400 cursor-pointer select-none hover:text-slate-600 transition-colors whitespace-nowrap ${sortKey === key ? 'text-primary' : ''}`;

  return (
    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className={thCls('name')} onClick={() => handleSort('name')}>
                <span className="flex items-center gap-1.5">
                  Học viên
                  <SortIcon column="name" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className="px-4 py-3.5 text-[10px] font-bold uppercase tracking-wider text-slate-400 whitespace-nowrap">
                Mã phiếu
              </th>
              <th className={thCls('paid')} onClick={() => handleSort('paid')}>
                <span className="flex items-center gap-1.5">
                  Đã đóng
                  <SortIcon column="paid" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className={thCls('total')} onClick={() => handleSort('total')}>
                <span className="flex items-center gap-1.5">
                  Tổng phí
                  <SortIcon column="total" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className={thCls('debt')} onClick={() => handleSort('debt')}>
                <span className="flex items-center gap-1.5">
                  Còn nợ
                  <SortIcon column="debt" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className={thCls('date')} onClick={() => handleSort('date')}>
                <span className="flex items-center gap-1.5">
                  Ngày thu
                  <SortIcon column="date" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className={thCls('status')} onClick={() => handleSort('status')}>
                <span className="flex items-center gap-1.5">
                  Trạng thái
                  <SortIcon column="status" sortKey={sortKey} sortDir={sortDir} />
                </span>
              </th>
              <th className="px-4 py-3.5 text-[10px] font-bold uppercase tracking-wider text-slate-400 text-right">
                Thao tác
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {isLoading ? (
              Array.from({ length: 5 }).map((_, i) => (
                <tr key={i}>
                  {Array.from({ length: 8 }).map((_, j) => (
                    <td key={j} className="px-4 py-4">
