        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect } from 'react';
import { X, Phone, MapPin, BookOpen, Calendar, Receipt, DollarSign, TrendingUp } from 'lucide-react';
import { getPaymentsByStudent } from '@/src/services/paymentService';

const fmt = (n: number | undefined | null) =>
  (n || 0).toLocaleString('vi-VN') + 'đ';

function ProgressBar({ value, max }: { value: number; max: number }) {
  const pct = max > 0 ? Math.min(100, Math.round((value / max) * 100)) : 0;
  const color = pct === 100 ? 'bg-emerald-500' : pct >= 50 ? 'bg-blue-500' : 'bg-amber-500';
  return (
    <div className="flex items-center gap-3">
      <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
        <div className={`h-full ${color} rounded-full transition-all duration-700`} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs font-black text-slate-600 tabular-nums w-10 text-right">{pct}%</span>
    </div>
  );
}

interface PaymentItem {
  _id?: string;
  received_fee?: number;
  payment_date?: string;
  is_tuition_account?: boolean;
  note?: string;
  course_student_id?: {
    _id?: string;
    fee?: number;
    paid_fee?: number;
    student_id?: {
      _id?: string;
      user_id?: {
        first_name?: string;
        last_name?: string;
        phone?: string;
      };
      region_id?: { name?: string };
    };
    course_id?: {
      name?: string;
    };
    enrollment_date?: string;
  };
}

interface TuitionDetailModalProps {
  item: PaymentItem | null;
  onClose: () => void;
}

export default function TuitionDetailModal({ item, onClose }: TuitionDetailModalProps) {
  const [studentPayments, setStudentPayments] = React.useState<any[]>([]);
  const [loadingPayments, setLoadingPayments] = React.useState(false);

  useEffect(() => {
    if (!item) return;
    const studentId = item.course_student_id?.student_id?._id;
    if (!studentId) return;
    setLoadingPayments(true);
    getPaymentsByStudent(studentId)
      .then(res => {
        if (res.success && res.data) {
          const items = res.data.items || res.data.docs || res.data.data || res.data;
          setStudentPayments(Array.isArray(items) ? items : []);
        }
      })
      .catch(() => setStudentPayments([]))
      .finally(() => setLoadingPayments(false));
  }, [item]);

  if (!item) return null;

  const cs = item.course_student_id || {};
  const student = cs.student_id?.user_id || {};
  const name = `${student.last_name || ''} ${student.first_name || ''}`.trim() || 'Ẩn danh';
  const phone = student.phone || '--';
