'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { Download, Plus } from 'lucide-react';
import { toast } from 'sonner';
import { getPayments, getPaymentStats, exportPayments } from '@/src/services/paymentService';
import TuitionSummaryCards from '@/src/components/tuition/TuitionSummaryCards';
import TuitionFilters, { TuitionFiltersState } from '@/src/components/tuition/TuitionFilters';
import TuitionTable from '@/src/components/tuition/TuitionTable';
import TuitionDetailModal from '@/src/components/tuition/TuitionDetailModal';
import AddPaymentModal from '@/src/components/tuition/AddPaymentModal';
import StudentDetailDrawer from '@/src/components/students/StudentDetailDrawer';
import { useAuth } from '@/src/context/AuthContext';

const LIMIT = 20;

export default function TuitionPage() {
  const { user } = useAuth();
  const [filters, setFilters] = useState<TuitionFiltersState>({
    search: '',
    status: '',
    dateFrom: '',
    dateTo: '',
  });
  const [payments, setPayments] = useState<any[]>([]);
  const [meta, setMeta] = useState<any>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [stats, setStats] = useState({
    total_received: 0,
    total_receivable: 0,
    total_debt: 0,
    debtor_count: 0,
  });
  const [isLoading, setIsLoading] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Modal/drawer state
  const [detailItem, setDetailItem] = useState<any>(null);
  const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
  const [isAddPaymentModalOpen, setIsAddPaymentModalOpen] = useState(false);
  const [selectedStudent, setSelectedStudent] = useState<any>(null);

  const fetchPayments = useCallback(async (page = 1) => {
    setIsLoading(true);
    try {
      const params: any = {
        page,
        limit: LIMIT,
        search: filters.search,
        status: filters.status,
      };
      if (filters.dateFrom) params.date_from = filters.dateFrom;
      if (filters.dateTo) params.date_to = filters.dateTo;

      const [res, statsRes] = await Promise.all([
        getPayments(page, LIMIT, params),
        getPaymentStats(),
      ]);

      if (res.success && res.data) {
        setPayments(res.data.items || res.data.docs || res.data.data || []);
        setMeta(res.data.pagination || res.data.meta);
      }

      if (statsRes.success && statsRes.data) {
        setStats(statsRes.data);
      }
    } catch (error: any) {
      toast.error('Lỗi khi tải dữ liệu học phí');
    } finally {
      setIsLoading(false);
    }
  }, [filters]);

  // Fetch on page / filter change
  useEffect(() => {
    fetchPayments(currentPage);
  }, [currentPage]);

  useEffect(() => {
    if (currentPage === 1) {
      fetchPayments(1);
    } else {
      setCurrentPage(1);
    }
  }, [filters]);

  // Refresh on payment events
  useEffect(() => {
    const handleRefresh = () => fetchPayments(1);
    window.addEventListener('refresh-student-list', handleRefresh);
    window.addEventListener('refresh-payment-list', handleRefresh);
    return () => {
      window.removeEventListener('refresh-student-list', handleRefresh);
      window.removeEventListener('refresh-payment-list', handleRefresh);
    };
  }, [fetchPayments]);

  const handleExport = async () => {
    setIsExporting(true);
    try {
      await exportPayments(filters);
      toast.success('Xuất dữ liệu Excel thành công');
    } catch (error) {
      toast.error('Lỗi khi xuất dữ liệu');
    } finally {
      setIsExporting(false);
    }
  };

  const openDetailModal = (item: any) => {
    setDetailItem(item);
    setIsDetailModalOpen(true);
  };

  return (
    <div className="flex flex-col gap-5 animate-in fade-in slide-in-from-bottom-2 duration-500">

      {/* Page header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-baseline gap-4">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <div className="w-1.5 h-6 bg-gradient-to-b from-primary to-indigo-600 rounded-full" />
            <h1 className="text-2xl sm:text-3xl font-black text-slate-900 tracking-tight leading-tight">
              Quản lý Học Phí
            </h1>
          </div>
          <p className="text-sm font-medium text-slate-400 ml-5">
            Theo dõi tình hình thu chi học phí &amp; công nợ
          </p>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button
            onClick={handleExport}
            disabled={isExporting}
            className="inline-flex items-center gap-2 px-4 py-2.5 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl hover:bg-slate-50 hover:border-slate-300 transition-all shadow-sm disabled:opacity-50 disabled:cursor-not-allowed text-sm"
          >
            {isExporting ? (
              <div className="w-4 h-4 border-2 border-slate-300 border-t-slate-600 rounded-full animate-spin" />
            ) : (
              <Download className="w-4 h-4" />
            )}
            Xuất CSV
          </button>
          <button
            onClick={() => setIsAddPaymentModalOpen(true)}
            className="inline-flex items-center gap-2 px-5 py-2.5 bg-primary text-white font-bold rounded-xl shadow-lg shadow-primary/25 hover:bg-primary/90 active:scale-95 transition-all text-sm"
          >
            <Plus className="w-4 h-4" />
            Thu tiền
          </button>
        </div>
      </div>

      {/* Summary cards */}
      <TuitionSummaryCards
        totalReceived={stats.total_received}
        totalReceivable={stats.total_receivable}
        totalDebt={stats.total_debt}
        debtorCount={stats.debtor_count}
        isLoading={isLoading}
      />

      {/* Filters */}
      <TuitionFilters filters={filters} onChange={setFilters} isLoading={isLoading} />

      {/* Table */}
      <TuitionTable
        payments={payments}
        meta={meta}
        currentPage={currentPage}
        isLoading={isLoading}
        onPageChange={setCurrentPage}
        onViewDetail={openDetailModal}
      />

      {/* Detail modal */}
      <TuitionDetailModal
        item={detailItem}
        onClose={() => {
          setIsDetailModalOpen(false);
          setDetailItem(null);
        }}
      />

      {/* Add payment modal */}
      <AddPaymentModal
        isOpen={isAddPaymentModalOpen}
        onClose={() => setIsAddPaymentModalOpen(false)}
        onSuccess={() => fetchPayments(1)}
      />

      {/* Student detail drawer */}
      <StudentDetailDrawer
        isOpen={!!selectedStudent}
        student={selectedStudent}
        onClose={() => setSelectedStudent(null)}
        defaultTab="hocphi"
      />
    </div>
  );
}

